'use client';

import { useState } from 'react';
import Image from 'next/image';
import { Gift, ArrowDown, ArrowLeft } from 'lucide-react';
import Link from 'next/link';
import { useStore } from '../lib/store';

const API_BASE = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3000/api';

export default function Dashboard() {
  const { fetchData } = useStore();

  const [isLogged, setIsLogged] = useState(false);
  const [pass, setPass] = useState('');

  const [donation, setDonation] = useState({
    donorName: '', donorPhone: '', donorAddress: '', donorImage: null,
    receiverName: '', receiverPhone: '', receiverAddress: '', receiverImage: null,
    amount: '', note: ''
  });

  const [expense, setExpense] = useState({
    receiverName: '', receiverPhone: '', receiverAddress: '', receiverImage: null,
    amount: '', note: ''
  });

  const [loading, setLoading] = useState(false);

  const handleLogin = () => {
    if (pass === 'admin123') setIsLogged(true);
    else alert('ভুল পাসওয়ার্ড!');
    setPass('');
  };

  const handleImageChange = (e, field, type) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (type === 'donation') {
      setDonation(prev => ({ ...prev, [field + 'Image']: file }));
    } else {
      setExpense(prev => ({ ...prev, [field + 'Image']: file }));
    }
  };

  const handleAddDonation = async () => {
    if (!donation.amount || !donation.donorName.trim() || !donation.receiverName.trim()) {
      return alert('দরকারি তথ্য পূরণ করুন');
    }

    setLoading(true);
    const formData = new FormData();
    formData.append('type', 'donation');
    formData.append('amount', donation.amount);
    formData.append('note', donation.note);
    formData.append('donorName', donation.donorName);
    formData.append('donorPhone', donation.donorPhone);
    formData.append('donorAddress', donation.donorAddress);
    if (donation.donorImage) formData.append('donorImage', donation.donorImage);
    formData.append('receiverName', donation.receiverName);
    formData.append('receiverPhone', donation.receiverPhone);
    formData.append('receiverAddress', donation.receiverAddress);
    if (donation.receiverImage) formData.append('receiverImage', donation.receiverImage);

    try {
      const res = await fetch(`${API_BASE}/hishab`, { method: 'POST', body: formData });
      if (!res.ok) throw new Error('দান যোগ করা যায়নি');
      alert('দান সফলভাবে যোগ হয়েছে');
      await fetchData();
      setDonation({ donorName:'', donorPhone:'', donorAddress:'', donorImage:null,
                    receiverName:'', receiverPhone:'', receiverAddress:'', receiverImage:null,
                    amount:'', note:'' });
    } catch (err) {
      alert('সমস্যা: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleAddExpense = async () => {
    if (!expense.amount || !expense.receiverName.trim()) {
      return alert('দরকারি তথ্য পূরণ করুন');
    }

    setLoading(true);
    const formData = new FormData();
    formData.append('type', 'expense');
    formData.append('amount', expense.amount);
    formData.append('note', expense.note);
    formData.append('receiverName', expense.receiverName);
    formData.append('receiverPhone', expense.receiverPhone);
    formData.append('receiverAddress', expense.receiverAddress);
    if (expense.receiverImage) formData.append('receiverImage', expense.receiverImage);

    try {
      const res = await fetch(`${API_BASE}/hishab`, { method: 'POST', body: formData });
      if (!res.ok) throw new Error('খরচ যোগ করা যায়নি');
      alert('খরচ সফলভাবে রেকর্ড হয়েছে');
      await fetchData();
      setExpense({ receiverName:'', receiverPhone:'', receiverAddress:'', receiverImage:null,
                    amount:'', note:'' });
    } catch (err) {
      alert('সমস্যা: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  if (!isLogged) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-900">
        <div className="bg-white/10 backdrop-blur p-10 rounded-3xl shadow-2xl max-w-md w-full">
          <h1 className="text-4xl font-bold mb-6 text-white text-center">অ্যাডমিন লগইন</h1>
          <input
            type="password"
            value={pass}
            onChange={e => setPass(e.target.value)}
            placeholder="পাসওয়ার্ড"
            className="w-full p-4 rounded-xl bg-white/20 border border-white/30 text-white placeholder-white/60 mb-4"
          />
          <button
            onClick={handleLogin}
            className="w-full bg-emerald-600 hover:bg-emerald-700 text-white py-4 rounded-xl text-xl"
          >
            লগইন
          </button>
          <p className="text-center text-gray-300 mt-4 text-sm">demo: admin123</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-6 md:p-10">
      <div className="max-w-7xl mx-auto">
        <Link href="/">
          <button className="flex items-center gap-2 bg-emerald-600 text-white px-6 py-3 rounded-xl mb-8 hover:bg-emerald-700">
            <ArrowLeft /> হোমে ফিরুন
          </button>
        </Link>

        <h1 className="text-5xl font-extrabold text-emerald-800 text-center mb-12">অ্যাডমিন ড্যাশবোর্ড</h1>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
          {/* দান ফর্ম */}
          <div className="bg-white p-8 rounded-3xl shadow-xl">
            <h2 className="text-3xl font-bold text-purple-800 mb-6 flex items-center gap-3">
              <Gift /> নতুন দান
            </h2>
            {/* ... inputs ... (আপনার আগের কোড অনুযায়ী রাখুন, শুধু handleImageChange ও handleAddDonation ব্যবহার করুন) */}
            <button
              onClick={handleAddDonation}
              disabled={loading}
              className="w-full bg-purple-600 text-white py-5 rounded-xl font-bold mt-6 disabled:opacity-50"
            >
              {loading ? 'যোগ হচ্ছে...' : 'দান যোগ করুন'}
            </button>
          </div>

          {/* খরচ ফর্ম */}
          <div className="bg-white p-8 rounded-3xl shadow-xl">
            <h2 className="text-3xl font-bold text-red-800 mb-6 flex items-center gap-3">
              <ArrowDown /> নতুন খরচ
            </h2>
            {/* ... inputs ... */}
            <button
              onClick={handleAddExpense}
              disabled={loading}
              className="w-full bg-red-600 text-white py-5 rounded-xl font-bold mt-6 disabled:opacity-50"
            >
              {loading ? 'যোগ হচ্ছে...' : 'খরচ যোগ করুন'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}